
USE fpt_admission;
CREATE TABLE IF NOT EXISTS high_schools (id BIGINT AUTO_INCREMENT PRIMARY KEY, name VARCHAR(300) NOT NULL, school_type ENUM('PUBLIC','PRIVATE') DEFAULT 'PUBLIC', province_id BIGINT NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (province_id) REFERENCES provinces(id));
SELECT COUNT(*) as total_schools FROM high_schools;
